import { useState, memo } from 'react';
import cls from './Register.module.scss';
import { isMobile } from 'react-device-detect';
import { Button, FieldRow, TaskBoardPanel } from '../../common';
import MessageContainer from '../ProcessesComps/MessageContainer/MessageContainer';
import { createNewCompany, checkCompany, createOpenUserInvite } from '../../../services/company.service';
import { take } from 'rxjs';
import { store } from '../../../reduxStore/store';
import { setMessageBar } from '../../../reduxStore/actions/flowActions';
import { APP_NAME } from '../../../shared/utility';
import { useNavigate } from 'react-router-dom';
import MessageBar from '../../TopBar/MessageBar';
import { useSelector } from 'react-redux';
import { checkUserEmail } from '../../../services/user.service';

const Register = memo(() => {
	const [newCompany, setNewCompany] = useState({ message: '' });
	const { showMessage } = useSelector(store => store.flowReducer);
	const { authenticated } = useSelector(store => store.authReducer);

	const [loading, setLoading] = useState(false);
	const [valid, setValid] = useState(false);

	const navigate = useNavigate();
	const createCompany = () => {
		if (newCompany.companyName && newCompany.displayName && newCompany.email && newCompany.firstName && newCompany.lastName && newCompany.slug) {
			setLoading(true);
			createNewCompany(newCompany)
				.pipe(take(1))
				.subscribe({
					next: () =>
						store.dispatch(
							setMessageBar({ noTimeout: true, show: true, message: `We have received your request for the creation of ${newCompany.companyName}. We will gladly review this. We will send an email notification to ${newCompany.email}`, action: () => navigate('/login') })
						),
					error: () => {
						setLoading(false);
						store.dispatch(setMessageBar({ show: true, message: `Fail! There is something wrong with the details you provided`, color: 'red', action: () => store.dispatch(setMessageBar({ show: false, message: `` })) }));
					},
					complete: () => setLoading(false),
				});
		}
	};

	const checkEmailCompany = () => {
		if (newCompany.email) {
			setLoading(true);
			checkUserEmail(newCompany)
				.pipe(take(1))
				.subscribe({
					next: data =>{
						store.dispatch(setMessageBar({ show: true, message: `Email already exists and being used. Please choose another email`, color: 'red', action: () => store.dispatch(setMessageBar({ show: false, message: `` })) }));
						setValid(false);
						setLoading(false);
					},
					error: () => {
						store.dispatch(setMessageBar({ show: true, message: `Email ${newCompany.email} is available for use.`, action: () => store.dispatch(setMessageBar({ show: false, message: `` })) }));
						setLoading(false);
						setValid(true);
						
					},
					
				});
		}
	};
	const renderSuperAdminCreateCompany = () => {
		return (
			<div>
				<FieldRow fieldLabel={'Email'} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, email: e.target.value });
							}}
							autoComplete="none"
							value={newCompany?.email}
							className={cls.fieldTypeInput}
							name={'Email'}
						/>
					</div>
				</FieldRow>
				<br/>
				<FieldRow fieldLabel={'Company Name'} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, companyName: e.target.value, displayName: e.target.value, slug: e.target.value.replace(' ', '').toLowerCase() });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Company Name'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'First Name'} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, firstName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'First Name'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'Last Name'} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, lastName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Last Name'}
						/>
					</div>
				</FieldRow>
			</div>
		);
	};

	return (
		<div style={{}}>
			<p
				onClick={() => navigate('/flowhero')}
				style={{
					cursor: 'pointer',
					fontFamily: 'var(--app-text-main-font)',
					color: '#4A4A4A',
					textDecoration: 'underline',
					paddingLeft: '10px',
					display: isMobile ? 'none' : '',
				}}
			>
				Home
			</p>
			{showMessage?.show && !authenticated && <MessageBar />}
			<div className={cls.centeredColumn} style={{border: '1px dashed var(--app-color-gray-lighter)', margin: 'auto', marginTop: '100px', width: isMobile ? '120%' : '20%', minWidth: '400px' }}>
				{newCompany?.message !== '' && <MessageContainer message={newCompany?.message} onClick={() => setNewCompany({ ...newCompany, message: '' })} />}

				<div className={cls.headerTopBarContainer} style={{ fontSize: isMobile ? '30px' : '40px', fontWeight: 'normal' }}>
					FLOW<span style={{ color: isMobile ? 'var(--app-color-blue)' : 'orange', fontWeight: 'normal' }}> HERO</span>™
				</div>

				<p className={cls.subheaders}>{'Sign-up your company, its quick and easy'}</p>
				<br />

				{valid ?
					renderSuperAdminCreateCompany()
					:
					<FieldRow fieldLabel={'Email'} visible={true}>
						<div className={cls.fieldRowContainer}>
							<input
								onChange={e => {
									setNewCompany({ ...newCompany, email: e.target.value });
								}}
								autoComplete="none"
								className={cls.fieldTypeInput}
								name={'Email'}
							/>
						</div>
					</FieldRow>
				}
				<div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', margin: '20px' }}>

					{valid ? <Button clicked={createCompany} title={'Sign me up'} loading={loading} /> :
						<Button clicked={checkEmailCompany} title={'Check email'} loading={loading} />}
				</div>
			</div>
		</div>
	);
});

export default Register;
